import React, { useState, useEffect } from 'react';
import api from '../lib/api';

const AuditLogs = () => {
  const [logs, setLogs] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState('all');

  useEffect(() => {
    loadLogs();
  }, []);

  const loadLogs = async () => {
    setLoading(true);
    try {
      const response = await api.get('/audit-logs/');
      setLogs(response.data.results || response.data || []);
    } catch (error) {
      console.error('Error loading logs:', error);
    } finally {
      setLoading(false);
    }
  };

  const getActionColor = (action) => {
    if (action?.includes('create') || action?.includes('CREATE')) return 'bg-green-600/20 text-green-400';
    if (action?.includes('update') || action?.includes('UPDATE')) return 'bg-blue-600/20 text-blue-400';
    if (action?.includes('delete') || action?.includes('DELETE')) return 'bg-red-600/20 text-red-400';
    return 'bg-gray-600/20 text-gray-400';
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-500"></div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-xl font-semibold text-white">Logs de Auditoria</h2>
          <p className="text-gray-400 text-sm">{logs.length} registros</p>
        </div>
        <select
          value={filter}
          onChange={(e) => setFilter(e.target.value)}
          className="bg-gray-800 border border-gray-700 rounded-lg px-4 py-2 text-white"
        >
          <option value="all">Todas as ações</option>
          <option value="create">Criações</option>
          <option value="update">Atualizações</option>
          <option value="delete">Exclusões</option>
        </select>
      </div>

      {logs.length === 0 ? (
        <div className="bg-gray-800 rounded-lg p-12 text-center">
          <span className="text-6xl mb-4 block">📋</span>
          <h3 className="text-xl font-medium text-white mb-2">Nenhum registro encontrado</h3>
          <p className="text-gray-400">As atividades aparecerão aqui</p>
        </div>
      ) : (
        <div className="bg-gray-800 rounded-lg border border-gray-700 overflow-hidden">
          <table className="w-full">
            <thead className="bg-gray-700">
              <tr>
                <th className="px-4 py-3 text-left text-sm font-medium text-gray-300">Data/Hora</th>
                <th className="px-4 py-3 text-left text-sm font-medium text-gray-300">Usuário</th>
                <th className="px-4 py-3 text-left text-sm font-medium text-gray-300">Ação</th>
                <th className="px-4 py-3 text-left text-sm font-medium text-gray-300">Detalhes</th>
                <th className="px-4 py-3 text-left text-sm font-medium text-gray-300">IP</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-700">
              {logs.map((log, index) => (
                <tr key={log.id || index} className="hover:bg-gray-700/50">
                  <td className="px-4 py-3 text-gray-400 text-sm">{log.timestamp || log.created_at || '-'}</td>
                  <td className="px-4 py-3 text-white">{log.user || log.username || 'Sistema'}</td>
                  <td className="px-4 py-3">
                    <span className={`px-2 py-1 rounded text-xs ${getActionColor(log.action)}`}>
                      {log.action || 'Ação'}
                    </span>
                  </td>
                  <td className="px-4 py-3 text-gray-300 text-sm max-w-md truncate">{log.details || log.description || '-'}</td>
                  <td className="px-4 py-3 text-gray-500 text-sm font-mono">{log.ip_address || '-'}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
};

export default AuditLogs;
